public boolean findRotation(int[][] mat, int[][] target) {
    for (int i = 0; i < 4; ++i) {
        if (Arrays.deepEquals(mat, target)) return true;
        int n = mat.length;
        for (int r = 0; r < (n + 1) / 2; ++r)
            for (int c = 0; c < n / 2; ++c) {
                int temp = mat[r][c];
                mat[r][c] = mat[n - 1 - c][r];
                mat[n - 1 - c][r] = mat[n - 1 - r][n - 1 - c];
                mat[n - 1 - r][n - 1 - c] = mat[c][n - 1 - r];
                mat[c][n - 1 - r] = temp;
            }
    }
    return false;
}
```

